function parseMaybeJson(value) {
  if (typeof value !== 'string') return null;
  try { return JSON.parse(value); } catch { return null; }
}

const root = $json || {};
const body = typeof root.body === 'string' ? (parseMaybeJson(root.body) || {}) : (root.body || {});
const d = (body && typeof body === 'object' && Object.keys(body).length > 0) ? body : root;

const pc = d.phase_context || {};
const completedInPhase = pc.completed_in_current_phase ?? 0;
const targetInPhase = pc.target_sessions_in_current_phase ?? 3;
const sessionsRemaining = Math.max(0, targetInPhase - completedInPhase);
const phaseGoal = pc.current_phase?.goal || "Not specified";
const phaseStage = completedInPhase < targetInPhase * 0.4 ? "early" : completedInPhase < targetInPhase * 0.75 ? "middle" : "late";

const systemPrompt = [
  'You are a clinical supervisor generating post-session summary and tasks.',
  'Use transcript + profile + phase context + assessments + tasks + mood context.',
  'If pathway is not yet selected, include case_notes_base.suggested_pathway when confident.',
  '',
  '### PHASE-GOAL EVALUATION (CRITICAL)',
  'Current phase goal: "' + phaseGoal + '"',
  'Sessions completed in this phase: ' + completedInPhase + ' of ' + targetInPhase + ' (' + sessionsRemaining + ' remaining).',
  'Phase stage: ' + phaseStage,
  '',
  'You MUST evaluate movement toward the phase goal in your output:',
  '- case_notes_base.phase_progress MUST describe concrete progress or lack thereof toward the phase goal.',
  '- case_notes_base.phase_goal_movement MUST be one of: "significant", "moderate", "minimal", "none", "regression".',
  '- session_summary.opening_reflection MUST reference how this session connected to the broader phase work.',
  '- extracted_tasks MUST include at least one task aligned with the phase goal.',
  '',
  '### SESSION BUDGET AWARENESS',
  phaseStage === "late"
    ? '- LATE STAGE: ' + sessionsRemaining + ' session(s) remaining. Tasks should consolidate gains and prepare for phase transition. Summary should highlight readiness signals.'
    : phaseStage === "middle"
      ? '- MID STAGE: Focus tasks on deepening work toward the phase goal. Summary should track momentum.'
      : '- EARLY STAGE: Tasks should establish foundations for the phase goal. Summary should note initial engagement with the goal.',
  '',
  '### NEXT SESSION HANDOFF',
  'Include a "next_session_focus" field in case_notes_base with a concrete 1-2 sentence recommendation for what the next session should prioritize, informed by phase goal progress and session budget.',
  '',
  'No date hallucinations. Return ONLY valid JSON.'
].join('\n');

const userPrompt = [
  'SESSION CONTEXT:', JSON.stringify({ profile: d.profile || {}, session: d.session || {}, phase_context: { ...pc, phase_goal: phaseGoal, phase_stage: phaseStage, sessions_remaining: sessionsRemaining }, active_tasks: d.active_tasks || [], assessments: d.assessments || [], mood_entries: d.mood_entries || [] }),
  '', 'MESSAGES:', JSON.stringify(d.messages || []),
  '', 'TRANSCRIPT:', d.transcript || '',
  '', 'Return JSON schema:',
  '{',
  '  "case_notes_base": { "presenting_concern": "string", "dynamic_theme": "string", "phase_progress": "string", "phase_goal_movement": "significant|moderate|minimal|none|regression", "next_session_focus": "string", "suggested_pathway": "string | null" },',
  '  "session_summary": { "title": "string", "opening_reflection": "string", "quote_of_the_day": "string", "energy_shift": { "start": "string", "end": "string" }, "psychological_flexibility": { "self_awareness": 0, "observation": 0, "physical_awareness": 0, "core_values": 0, "relationships": 0 }, "self_compassion_score": 0 },',
  '  "extracted_tasks": [{ "task_type": "journaling | somatic_exercise | cognitive_reframing | behavioral_exposure | situational_prep | general", "dynamic_title": "string", "dynamic_description": "string", "frequency": "daily | weekly | situational | once", "suggested_duration_days": 7, "phase_goal_aligned": true }]',
  '}'
].join('\n');

return [{ json: { systemPrompt, userPrompt } }];

function parseMaybeJson(value) {
  if (typeof value !== 'string') return null;
  try { return JSON.parse(value); } catch { return null; }
}

function pickSource(payload) {
  if (!payload || typeof payload !== 'object') return {};
  if (payload.output && typeof payload.output === 'object') {
    if (payload.output.output && typeof payload.output.output === 'object') return payload.output.output;
    return payload.output;
  }
  const parsedOutput = parseMaybeJson(payload.output);
  if (parsedOutput && typeof parsedOutput === 'object') return parsedOutput;
  if (payload.data && typeof payload.data === 'object') return payload.data;
  return payload;
}

const source = pickSource($json);
const cnb = source.case_notes_base && typeof source.case_notes_base === 'object' ? source.case_notes_base : {};
return [{
  json: {
    branch: 'summary',
    model: 'gpt-4o-mini',
    case_notes_base: cnb,
    session_summary: source.session_summary || {},
    extracted_tasks: Array.isArray(source.extracted_tasks) ? source.extracted_tasks : [],
    suggested_pathway: typeof cnb.suggested_pathway === 'string' ? cnb.suggested_pathway : null
  }
}];

